#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define DATABASE_FILE "bank_db.dat"

#pragma pack(push, 1)
typedef struct {
    uint32_t account_num;
    uint16_t pin_hash;
    double balance;
    char holder_name[50];
} AccountRecord;
#pragma pack(pop)

/* Simple XOR Hash for Pin Security Demonstration */
uint16_t encrypt_pin(uint16_t raw_pin) {
    return raw_pin ^ 0xA5A5;
}

int register_account(uint32_t acc_num, uint16_t pin, double initial_deposit, const char *name) {
    FILE *file = fopen(DATABASE_FILE, "ab+");
    if (!file) {
        perror("Database access failed");
        return 0;
    }

    AccountRecord new_acc;
    new_acc.account_num = acc_num;
    new_acc.pin_hash = encrypt_pin(pin);
    new_acc.balance = initial_deposit;
    strncpy(new_acc.holder_name, name, sizeof(new_acc.holder_name) - 1);
    new_acc.holder_name[sizeof(new_acc.holder_name) - 1] = '\0';

    size_t written = fwrite(&new_acc, sizeof(AccountRecord), 1, file);
    fclose(file);
    return written == 1;
}

int verify_and_transact(uint32_t acc_num, uint16_t pin, double amount, int is_deposit) {
    FILE *file = fopen(DATABASE_FILE, "r+b");
    if (!file) {
        perror("Database connection offline");
        return 0;
    }

    AccountRecord temp;
    int found = 0;
    long record_offset = 0;

    while (fread(&temp, sizeof(AccountRecord), 1, file)) {
        if (temp.account_num == acc_num) {
            found = 1;
            break;
        }
        record_offset += sizeof(AccountRecord);
    }

    if (!found) {
        printf("Account not found.\n");
        fclose(file);
        return 0;
    }

    if (temp.pin_hash != encrypt_pin(pin)) {
        printf("Invalid security pin code access denied.\n");
        fclose(file);
        return 0;
    }

    if (is_deposit) {
        temp.balance += amount;
    } else {
        if (temp.balance < amount) {
            printf("Insufficient liquidity inside account.\n");
            fclose(file);
            return 0;
        }
        temp.balance -= amount;
    }

    /* Seek backward to the exact structure offset in binary file */
    if (fseek(file, record_offset, SEEK_SET) != 0) {
        printf("Disk seek structural mapping failure.\n");
        fclose(file);
        return 0;
    }

    fwrite(&temp, sizeof(AccountRecord), 1, file);
    printf("Transaction successfully verified. Updated balance: $%.2f\n", temp.balance);
    fclose(file);
    return 1;
}

int main(void) {
    /* Clear any existing database for a clean simulation run */
    remove(DATABASE_FILE);

    printf("[ATM Admin] Registering Test Accounts...\n");
    register_account(100102, 1234, 500.50, "Alice Vance");
    register_account(100103, 5678, 2500.00, "Bob Miller");

    printf("\n[ATM Client Interface] Processing Bob's ATM Withdrawal Request...\n");
    verify_and_transact(100103, 5678, 300.00, 0); 

    printf("\n[ATM Client Interface] Processing Bob's Deposit Request...\n");
    verify_and_transact(100103, 5678, 150.00, 1);

    printf("\n[ATM Client Interface] Triggering Security Failure (Wrong PIN)...\n");
    verify_and_transact(100102, 9999, 50.00, 0);

    return 0;
}

