#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <netdb.h>

#define BUFFER_SIZE 2048

void fetch_web_page(const char *hostname, const char *path) {
    int socket_fd;
    struct hostent *server;
    struct sockaddr_in server_addr;
    char request[BUFFER_SIZE];
    char response[BUFFER_SIZE];
    ssize_t bytes_sent, bytes_received;

    /* Step 1: Create a raw TCP IPv4 stream socket */
    socket_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (socket_fd < 0) {
        perror("Failed to create network socket");
        return;
    }

    /* Step 2: Resolve Domain Name via DNS */
    server = gethostbyname(hostname);
    if (server == NULL) {
        fprintf(stderr, "Error: Unable to resolve hostname: %s\n", hostname);
        close(socket_fd);
        return;
    }

    /* Step 3: Configure Destination Address Structure */
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(80); /* Web server standard HTTP port */
    memcpy(&server_addr.sin_addr.s_addr, server->h_addr_list[0], (size_t)server->h_length);

    /* Step 4: Establish Active Three-Way TCP Handshake */
    if (connect(socket_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("TCP handshake failed");
        close(socket_fd);
        return;
    }

    /* Step 5: Format RFC-Compliant HTTP GET Request */
    snprintf(request, sizeof(request),
             "GET %s HTTP/1.1\r\n"
             "Host: %s\r\n"
             "User-Agent: C-MiniBrowser/1.0\r\n"
             "Connection: close\r\n\r\n",
             path, hostname);

    /* Step 6: Dispatch Request Payload */
    bytes_sent = send(socket_fd, request, strlen(request), 0);
    if (bytes_sent < 0) {
        perror("Failed to write payload to network buffer");
        close(socket_fd);
        return;
    }

    printf("[Network] Request successfully piped. Awaiting response streams...\n\n");

    /* Step 7: Continuous Stream Parsing of Inbound TCP Packets */
    while ((bytes_received = recv(socket_fd, response, BUFFER_SIZE - 1, 0)) > 0) {
        response[bytes_received] = '\0';
        /* Output standard web page response bytes directly to terminal output */
        printf("%s", response);
    }

    if (bytes_received < 0) {
        perror("Socket stream read error occurring during transmission");
    }

    /* Step 8: Close network socket to free system resources */
    close(socket_fd);
}

int main(void) {
    printf("[Browser Mini Project] Requesting httpbin.org root path content...\n");
    /* Use a stable, mock-safe site for raw textual response */
    fetch_web_page("httpbin.org", "/ip");
    return 0;
}

